```csharp
using UnityEngine;
using System.Collections.Generic;

public class ModelSlicer : MonoBehaviour
{
    public GameObject modelToSlice; // 需要剖切的模型
    public List<Vector3> slicePlaneNormals; // 剖切平面的法向量列表
    public List<Vector3> slicePlanePositions; // 剖切平面上的一个点列表

    private List<GameObject> slicedModels; // 剖切后的模型列表

    private void Start()
    {
        slicedModels = new List<GameObject>();
        SliceModel();
    }

    private void Update()
    {
        // 按下指定键导入剖切后的模型
        if (Input.GetKeyDown(KeyCode.I))
        {
            ImportSlicedModels();
        }

        // 按下指定键导出剖切后的模型
        if (Input.GetKeyDown(KeyCode.O))
        {
            ExportSlicedModels();
        }
    }

    private void SliceModel()
    {
        // 获取模型的Mesh
        Mesh mesh = modelToSlice.GetComponent<MeshFilter>().mesh;

        // 遍历所有剖切平面
        for (int i = 0; i < slicePlaneNormals.Count; i++)
        {
            // 创建一个剖切平面
            Plane slicePlane = new Plane(slicePlaneNormals[i], slicePlanePositions[i]);

            // 进行剖切
            SlicedMeshData slicedMeshData = mesh.Slice(slicePlane);

            // 创建剖切后的模型
            GameObject slicedModel = CreateSlicedModel(slicedMeshData.mesh, "Sliced Model " + i);

            // 将剖切后的模型放置在正确的位置
            slicedModel.transform.position = modelToSlice.transform.position;

            // 添加到剖切模型列表
            slicedModels.Add(slicedModel);
        }
    }

    private GameObject CreateSlicedModel(Mesh mesh, string modelName)
    {
        // 创建一个新的游戏对象
        GameObject slicedModel = new GameObject(modelName);

        // 添加MeshRenderer和MeshFilter组件
        MeshRenderer meshRenderer = slicedModel.AddComponent<MeshRenderer>();
        MeshFilter meshFilter = slicedModel.AddComponent<MeshFilter>();

        // 设置剖切后的Mesh和材质
        meshFilter.mesh = mesh;
        meshRenderer.material = modelToSlice.GetComponent<MeshRenderer>().material;

        return slicedModel;
    }

    private void ImportSlicedModels()
    {
        // 遍历剖切模型列表
        foreach (GameObject slicedModel in slicedModels)
        {
            // 导入剖切后的模型
            Instantiate(slicedModel);
        }
    }

    private void ExportSlicedModels()
    {
        // 遍历剖切模型列表
        foreach (GameObject slicedModel in slicedModels)
        {
            // 将剖切后的模型导出为OBJ格式
            ObjExporter.Export(slicedModel);
        }
    }
}
```

请注意，上述示例中使用了一个名为`ObjExporter`的工具类来导出剖切后的模型为OBJ格式。您可以在Unity Asset Store等资源库中找到相关的OBJ导出工具类，或自行编写该功能。

